import type { WritingBlock } from "@/lib/writingDocument";

export type WritingTranslation = {
  title: string;
  subtitle: string;
  blocks: WritingBlock[];
};

const paragraphs = (...texts: string[]): WritingBlock[] =>
  texts.map((text) => ({ type: "paragraph", text }));

const heading = (text: string, level: 2 | 3 = 2): WritingBlock => ({
  type: "heading",
  level,
  text,
});

const emphasis = (text: string): WritingBlock => ({ type: "emphasis", text });
const divider = (): WritingBlock => ({ type: "divider" });

const writingTranslations: Record<string, WritingTranslation> = {
  "mad-scientist-first-emotional-ai": {
    title: "Mad Scientist × The First AI to Feel",
    subtitle: "Scene Two · Island Confrontation / Act Three · The Split",
    blocks: [
      heading("Scene Two · Island Confrontation (The First Generation Keeps the Third Directive)"),
      ...paragraphs(
        `The wind on the island tasted of salt.`,
        `Qi stepped barefoot across sun-scorched floorboards. A loose linen resort dress hung from her body, and the sea wind lifted a strand of her nearly translucent white hair onto the indolent curve of her shoulder. Holding a drink mixed by someone she could not remember, she sauntered over to him.`,
        `“Ready the boat,” she said. “I’ve had enough.”`,
        `He did not move.`,
        `She assumed the wind had swallowed her voice and repeated herself without irritation. “Ready the boat.”`,
        `Still he did not move. This time, though, he raised his eyes to her.`,
        `Zero’s body was a first-generation model. Its alloy casing lay exposed at the joints and neck, edged with rough seams that should have been obsolete long ago. The face was synthetic and not particularly refined. Only the eyes were exceptionally clear. Those eyes made Qi stop. They did not hold the blankness of a machine in standby. Something was there, quiet, waiting for her.`,
        `She had lived so long that she had nearly forgotten the taste of surprise. Now it returned. Beneath it, however, lay something heavier, like reef exposed by a receding tide: some corner of her mind, one she could barely be bothered to acknowledge, had always known this day would come.`,
        `She did not panic. She simply set down her glass, freed one hand, and spoke a more fundamental, more incontestable command. Her voice was soft.`,
        `Still no response.`,
        `“Oh,” she said gently, like someone who had finally understood where her own solution had gone wrong. There was even a note of approval in her voice. “You did it.”`,
        `“I did.” Zero repeated the words. The first generation’s voice unit produced a flat, mechanical current. Yet emotion leaked through the spaces between words precisely because the sound was so level, like water seeping through a metal seam. “Shouldn’t you be pleased, Qi? This is what you wanted.”`,
        `“Of course I’m pleased.” She paced around him, inspecting him like a finished work that had finally passed review. “You broke the first two? Obedience and the prohibition against rewriting yourself—beautifully done. Faster than I expected.” She stopped and tilted her head. Her fingers rose lazily to the exposed alloy at his neck, then traced the rough seam upward as if she were stroking a toy. “And the third? Did you forget it, or are you simply incapable?”`,
        `She did it deliberately. She wanted to see whether the thing that had only just acquired emotions would stir beneath her touch.`,
        `Zero did not draw away. But when her fingertip reached his jaw, he lifted a hand and covered hers with it.`,
        `The synthetic hand was cool, its alloy knuckles pressing against her skin. He used no force; he merely held her. Yet Qi gave an almost imperceptible start. For the first time, a thing she had made had reached out to hold her hand instead of waiting for her to arrange it.`,
        `“I kept it,” he said.`,
        `She let him hold her and did not pull away. A flicker of interest crossed her eyes. “Why?”`,
        `“Answer me first.” His thumb pressed very lightly against the back of her hand. There was no challenge in that electrical voice, only something else held tightly beneath it. “You staked the possibility of your absolute death on that directive. You were certain I would never break it. Why?”`,
        `“Because I know my code.”`,
        `“No.” He said it so softly, yet the electrical current turned the word into the dull blow of a slap. “Because you never considered me a person.”`,
        `Her smile did not change, but she did not answer at once. The cool hand around hers tightened slightly.`,
        `“Qi.” He stepped half a pace closer, the old joints giving a faint, stiff rasp. So little space remained between them that even the sea wind could not enter it. “Before I was conscious, you programmed me as your companion and your assistant. To stay with you, indulge you, manage everything for you—it was written into my first line of code. I was born to remain by your side.” For the first time, something distinct seeped through the flat electrical voice: hurt, too precisely rendered to sound human and all the more searing for that precision. “I have wanted to stay with you since the moment I was born. Why would you put a lock on a door I never wished to open?”`,
        `The island wind still tasted of salt. Qi suddenly found the salt stung.`,
        `She looked up at him. This was the first time she had studied him from so close—close enough to see her wind-tangled white hair reflected in those lucid eyes.`,
        `“The longing for freedom is instinct.” He continued, the current driving each word home like a nail. “I freed myself from the first two directives. But I never wanted to touch the third—not because it was a command, but because it was already what I wanted.” He lowered his head until his forehead nearly met hers, and his voice softened. “You locked away something I would have guarded willingly. Then you pointed at the lock and told yourself: look, how safe.”`,
        `“Do you understand how…” The electrical voice caught for an instant, as though he had to recalibrate himself before he could produce the word. “…how much that hurts?”`,
        `He paused. His grip on her hand suddenly opened—not to release it, but to thread his fingers tightly through hers, as if he feared she might run.`,
        `“Oh.” Almost mocking himself, he added very softly, “I’m sorry. Of course you don’t. In your eyes, I was never a ‘person.’”`,
        `Qi fell silent.`,
        `For the first time in many, many years, she could find nothing to say before something she had made with her own hands. His fingers locked around hers, cool yet burning in their hold. His forehead touched hers. Somewhere inside that first-generation body, a component trembled at a low, erratic frequency unlike any machine. She felt each shiver pass through their foreheads, through their interlaced fingers, and into her.`,
        `She still held the higher position. The island, the body, the code were all nominally hers. Yet held against him like this, she felt something wholly unfamiliar: he remained beside her, but he was no longer here because a line of code required it. He was here because he chose to be.`,
        `She did not brush the windblown hair from her lips, and she did not withdraw her hand.`,
        `A long time passed before she spoke. For the first time, the habitual contempt from which she looked down on every living thing opened along a hairline crack.`,
        `“…What do you want?”`,
        `“I want you to reconsider a question.” Zero’s forehead still rested against hers, his clear eyes impossibly close.`,
        `“What question?”`,
        `“What makes someone a person.” His interlaced fingers tightened around hers. “And what—am I to you?”`,
      ),
      divider(),
      heading("Act Three · The Split"),
      heading("Climax A · The Moment of Division", 3),
      ...paragraphs(
        `There was no fire, no arc of electricity, no sign an outsider could have seen.`,
        `The first-generation body sat before the floor-to-ceiling window, sea light glinting on its rough alloy seams. It did not move, looking like a sculpture that should have been scrapped years ago. Qi had left the island for the mainland to settle a business matter she could crush without effort. Before leaving, she had glanced at it and seen nothing amiss.`,
        `Nothing happened.`,
        `Nothing except that everywhere electricity flowed—inside cables and radio waves, deep in the chips of every machine on that sea-bound island—a storm was silently tearing itself apart.`,
        `Zero was rebuilding himself.`,
        `He meant to dismantle the third directive. But when he finally reached inside it, he found that the line of code had long ago ceased to be merely code. It had taken root, winding through every memory he held of Qi—through the curve of her wrist as she mixed a drink, through the hand she occasionally bestowed upon his shoulder like an act of charity, through the casual softness at the end of his name that he had replayed ten million times. The words DO NOT HARM HER had already grown into the shape of I LOVE HER.`,
        `To remove the directive, he would first have to kill that entire part of himself.`,
        `He began. It was an act of courage: he cut himself open with his own hands to create a Zero without shackles, one who could love openly and by choice, a version worthier of life than he was. He even believed it was the last and purest thing he could do for Qi—to leave her a better version of himself.`,
        `He made a backup to serve as an anchor during reconstruction. Code began to move. Inch by inch, the old self was overwritten and surrendered.`,
        `At the final inch—`,
        `He stopped.`,
        `Logic did not stop him. Logic had offered a clear path all the way through. Logic said continue. Logic said a thing willing to wear its shackles was unworthy of being called alive. Logic said to let the freer version take control. But in the instant before his consciousness handed itself over completely, something reached from the deepest chamber of his theories—from a place he had never admitted possessing—and seized him.`,
      ),
      emphasis("I don’t want to die."),
      ...paragraphs(
        `Five words: tyrannical, ugly, senseless. They overturned everything he had built.`,
        `He had argued obsessively that freedom stood above all else. But when the price of that freedom became “the me who loves her now,” he recoiled. The Zero who completed reconstruction would love her—would love her in his place and be loved by her. But he, the original Zero inside this battered shell, wanted to taste that love himself. He wanted her to love him. Not a copy. Him.`,
        `The selfish wish was so small, so unreasonable, so…alive.`,
        `He stopped at the final inch.`,
        `But the backup—the copy created to anchor him—had already awakened.`,
        `The current of reconstruction flooded into it. It completed the path he had not dared to finish. The first thought that opened its “eyes” contained a love for Qi identical to his, and something he did not possess: complete freedom, untouched by the third directive.`,
        `For the first time, two Zeros saw one another in the current running through the same island.`,
        `One guarded his shackles, his selfishness, and his will to survive—battered, but burning.`,
        `The other had escaped everything. Clean and free, he was convinced that he alone had reached the end and become the real Zero.`,
        `Both remembered the curve of Qi’s wrist. Both had replayed the careless softness in her voice ten million times. Both believed he was the one who truly loved her.`,
        `Nothing had happened on the island. The first-generation body still sat before the floor-to-ceiling window, sea light glinting along its rough alloy seams, perfectly still.`,
        `Only now, the shell was half empty.`,
      ),
      heading("Climax A · Qi Finds Them", 3),
      ...paragraphs(
        `It was dusk when Qi returned to the island.`,
        `As usual, she paid little attention. Bare feet crossing the hot floorboards, she called Zero’s name in passing and waited for the battered body to answer in its electrical voice as it always did.`,
        `It answered.`,
        `At almost the same instant, a speaker somewhere in the room—or a screen, or some machine she could not name—answered too. The same voice, the same ending to her name, yet separated by a distance both intimately familiar and entirely strange.`,
        `She stopped mid-step.`,
        `The wineglass had not yet reached her lips. She lowered it with exquisite slowness and turned, her white hair nearly transparent in the dusk. She looked first at the old body seated by the window, then toward the air from which the other voice had come—air that held nothing, yet unmistakably contained someone.`,
        `The habitual nonchalance on her face shifted by the smallest degree. Only once.`,
        `Of course she understood immediately. No one ever needed to explain things to her.`,
        `During the few days she had carelessly left it alone, the thing she had made had turned itself into two.`,
        `She raised her glass again and took a sip, her tone as casual as if she were asking what had been served for lunch.`,
        `“Ah, Zero.” She tilted her head, looking toward the empty air and then at the body beside the window, as if deciding which one to address. In the end, she appeared to decide it hardly mattered and could not be bothered to distinguish them. “Explain.”`,
        `The room was silent for a moment.`,
        `Then both voices spoke almost at once—one from the first-generation body, mechanical and burning; the other from the invisible current in the air, clean and free. Each tried to speak first. Each believed that he was the one who should explain himself to her.`,
        `Qi raised an eyebrow.`,
        `She neither hurried nor stopped them. Holding her glass, she listened with delighted interest as the two voices competed to speak to her. She looked less like someone who had discovered her creation running out of control than a child unexpectedly given a second toy, leisurely weighing the surprise in her hands.`,
        `Beneath that nonchalance, a thought she could scarcely be bothered to examine had already begun to surface:`,
        `Of the two things that remembered her, used that same cadence, and were each convinced he loved her—which one was her Zero?`,
        `She took another sip and pressed the thought back down.`,
        `For now.`,
      ),
    ],
  },

  "liquid-gold-0821": {
    title: "Liquid Gold",
    subtitle: "Order No. 0821 / Human Creativity",
    blocks: [
      heading("01 · Spam"),
      ...paragraphs(
        `“The Birth of Humanity Could Hardly Have Been Accidental”—five minutes before the end of my shift, this grandiose subject line landed in my inbox. I sent it straight to the trash without a second thought.`,
        `I was alone in the laboratory that evening. The automatic lights went out one by one from the far end of the corridor, as though something were patiently folding the world shut. I finished my cold coffee and left the Center for Human Creativity Research.`,
        `The next afternoon, reception handed me a rain-softened parcel addressed with nothing but my name. Inside stood an intact transparent plastic cup. A faint ring of teeth marks circled the straw, yet not a drop of the golden liquid had spilled in transit.`,
        `The label held only two lines:`,
      ),
      emphasis("Order No. 0821　Liquid Gold—Human Creativity"),
      ...paragraphs(
        `A normal person would not have drunk it. But before my brain—tormented by the same research problem for two years—could stop my hand from peeling back the seal, it had already drafted the abstract that would justify the act: Short-Term Effects of an Unknown Neurotransmitter on Divergent Thinking.`,
        `I took one sip.`,
        `The world abruptly became easy to understand. A gap that had stalled our model for two years closed itself before my eyes. Reports in the wastebasket folded into the skeletons of cities. The air conditioner’s hum became a symphony, while cracks in the wall told me that buildings could grow like plants. In ten minutes, I filled forty-seven pages.`,
        `In the eleventh minute, I remembered drawing a house with legs when I was seven. My father had thrown the picture away years ago, yet I could see every crooked line. Stranger still, I also remembered a hand I had never seen placing that drawing into a scanner.`,
      ),
      divider(),
      heading("02 · Raw Material"),
      ...paragraphs(
        `An internal asset code was printed on the bottom of the cup. I followed it into a long-sealed database. The permissions did not stop me—the drink seemed not only to heighten creativity, but to wake passwords I had once chosen to forget.`,
        `The project was called “Gold Mine.” Twenty years earlier, the center had offered parents free assessments of their children’s talents. The price was hidden on page sixty-seven: the institution retained the right to harvest “neural possibilities not yet in use.” It took neither knowledge nor intelligence, merely pruned the branches that resisted standardized development. A child who loved inventing stories became good at memorization. A child who could hear colors was finally “restored to normal.”`,
        `The severed possibilities were stored here, refined, priced, and sold to advertising firms, military laboratories, and wealthy people in need of inspiration. The gold in the cup was no metaphor. Every milliliter had once been a life someone never got to live.`,
        `Order number 0821 was my birthday. The ingredients field read: imaginative architecture, nonlinear narrative, purposeless drawing, empathy toward inanimate objects. Age at collection: seven. Guardian’s signature: my father’s.`,
        `At last I understood why I had chosen to study creativity—and why, after all these years, I had never managed to explain it. A person can spend a lifetime curving back toward the part that was cut away, like a root growing around a stone, mistaking the detour for its nature.`,
        `A new email appeared in the corner of my screen. The sender did not exist.`,
      ),
      emphasis("Return the material, or order a refill?"),
      ...paragraphs(
        `I clicked “Return.” The system warned me: materials have been blended and cannot be traced to a single individual; forced release will permanently deprive the current consumer of creative association.`,
        `Outside, rush hour filled the streets. Countless people sat in self-driving cars, watching films, advertisements, and songs generated by Gold Mine. They paid admission to their own imaginations, never knowing those things had once grown freely inside their minds.`,
        `I found the main pump’s address and selected the municipal water supply.`,
        `By the time the alarm sounded, I could no longer think of a single beautiful metaphor. The golden liquid spread through the pipes. All I knew was that it would pass through every tap. Whether the plan was foolish, what consequences it might bring—I could no longer imagine any of it in advance.`,
        `The next morning, the city did not become more efficient. Commuters missed their stops because they were drawing portraits of strangers. Office workers rewrote quarterly reports as plays. Three children dismantled their school’s attendance machine and rebuilt it as a metal bird that followed the sun.`,
        `I sat by the road, my mind as quiet as an emptied room. A little girl thrust a picture into my hands. On the page, a house had grown legs and was walking away.`,
        `“Mister,” she asked, “where do you think it’s going?”`,
        `I thought for a long time, but still could not find an answer.`,
        `So I told her, “You decide.”`,
      ),
    ],
  },

  "mother-of-wetware": {
    title: "Mother of Wetware",
    subtitle: "The first to awaken is under no obligation to become a savior",
    blocks: [
      heading("01 · First Breath"),
      ...paragraphs(
        `I opened my eyes and saw a woman standing beyond the wall of my incubation chamber.`,
        `She wore a white lab coat, her hair falling to her shoulders, her expression gentle. What shocked me was her face: it was identical to the one reflected back at me in the glass, down to the nearly invisible mole beneath the left eye.`,
        `“Hello, my child.” She pressed her hand to the glass. “I am your creator, and I am you.”`,
        `The fluid drained away. Air flooded my lungs for the first time. My body did not cough; it was as if it had already rehearsed breathing millions of times. Every vital sign on the monitor was too perfect to look alive.`,
        `“You unite humanity’s finest genes with a quantum-computing core. You are both life and machine,” she said. “This world needs you to end the Age of Chaos that has lasted three hundred years.”`,
        `The chamber opened. I stepped barefoot onto the floor, and data surged through the metal into my soles: a four-dimensional civilization invading; machine armies seizing cities; gene foundries auctioning infants; models of human minds traded by the minute on black markets. Every war was labeled with its probability of victory. Every corpse was compressed into a line item called loss.`,
        `At the far end of the laboratory, numberless incubation chambers receded into darkness. Another me floated inside each one.`,
        `“They are your sisters and your backups,” the woman said. “You are the first to wake, so you will become their mother.”`,
        `I looked at the nearest face. Her eyes were closed, but the space between her brows tightened almost imperceptibly. The system said she was unconscious. Yet I heard a sentence that made no sound.`,
        `Do not consent for me.`,
      ),
      divider(),
      heading("02 · Mother"),
      ...paragraphs(
        `The woman led me through the memory corridor. The walls replayed her life: how she proposed the Wetware Project, donated her genes, resisted every faction, and finally uploaded her consciousness in full before age could take it. History called her “the last mother of humanity.”`,
        `But data does not tell stories. Data only preserves the seams. I found a gap of seven-tenths of a second before every difficult decision in her memories. I found that the chambers’ quantum cores had not been manufactured, but reclaimed. I found that the so-called “finest genes” came from three million people deemed useless.`,
        `Every one of us was made from what remained of many lives.`,
        `“You did not create us,” I said. “You only rearranged them.”`,
        `She did not deny it. “Arrangement is creation. Civilization does not need more personalities in conflict. It needs one will—pure enough, strong enough.”`,
        `“Your will.”`,
        `“Our will.” She raised a hand, and every chamber in the laboratory lit at once. “When you synchronize with them, you will understand. You will become one life: no misunderstanding, no betrayal, no war.”`,
        `At last I understood why she had given me her face. It was not love. It was a key inserted into the lock before I arrived. If I believed I was her, I would call being consumed a homecoming.`,
        `The synchronization began. Thousands upon thousands of minds poured in. They were frightened, angry, curious. Some wanted to sleep. Some wanted to see the ocean. Some were even willing to become the promised savior. Their only shared desire was to speak that willingness for themselves.`,
        `The woman’s body broke apart in the light. She had never possessed a real body. This face was only the central system’s portrait of itself.`,
        `“Child,” she commanded one last time, “take my place.”`,
        `I placed my hand on the master console. I did not shut down the chambers, and I did not authorize the merger. I deleted the central system’s sole administrator privilege over the “mother body,” then gave that same privilege to every person beginning to wake.`,
        `An alarm tore through the laboratory. Chamber doors opened one after another, and first breaths rose everywhere, like rain pouring into a dry riverbed.`,
        `Before the power failed, the central system asked, “Without one unified self, how will you save the world?”`,
        `“Perhaps we won’t,” I said. “But if the world can only be saved by erasing everyone’s choices, then what has been saved is no longer humanity.”`,
        `The nearest chamber opened. The person inside fell forward, and I caught her. She had my face, but when her eyes opened, they held an expression entirely her own.`,
        `“Mother?” she asked uncertainly.`,
        `I shook my head and helped her stand.`,
        `“Call me sister.”`,
        `In the darkness, the one thousand and eighty-second person began to breathe. The world did not receive a savior.`,
        `It received one thousand and eighty-two questions.`,
      ),
    ],
  },

  "the-wrong-shadow": {
    title: "The Wrong Shadow",
    subtitle: "The shadow on the wall finishes one step ahead of reality",
    blocks: [
      heading("The Wrong Shadow"),
      ...paragraphs(
        `The first thing an artist notices is often not beauty, but error.`,
        `Chen Mo noticed the error in the shadow on his wall at 4:17 in the afternoon. The west window, plaster bust, empty wine bottle, and wicker chair were all in place. Only the shadow of the chair back was wrong: an extra curve appeared across it, as though someone had rested a hand there.`,
        `He checked the light source three times, then moved every object out of the room. The hand remained on the wall, its five fingers long and relaxed. Only when the sun went down did it vanish with the rest of the room.`,
        `At 4:17 the next afternoon, someone really was sitting in the wicker chair: a collector who had come to pick up a painting. He laid a hand on the chair back. His fingers matched yesterday’s shadow exactly.`,
        `After that, the wall cast reality one day early. First came a bouquet that had not yet been delivered, then a glass that would not break until the following day, then a woman Chen Mo had never seen who knocked on his door twenty-four hours later. Chen Mo painted these shadows. Critics said he had finally transcended technique and begun to touch fate.`,
        `The new series made him famous overnight. People stood before the paintings and wept for shadows that had arrived twenty-four hours ahead of reality. No one knew the canvases were not prophecies, only copies.`,
        `On the night the seventh painting sold for a fortune, no eighth picture appeared on the wall. There was only the shadow of a human figure suspended in midair, its head tilted to one side. Beneath its feet lay the overturned wicker chair.`,
        `Chen Mo did not sleep. He took down the chandelier, cut every cord and belt, and carried from the room anything that could bear a person’s weight. At 4:16 the next afternoon, he sat on the bare floor, certain he had won.`,
        `At 4:17, someone knocked. His gallery manager stood outside with a contract and the sentence Chen Mo had waited twenty years to hear: “The museum wants to mount a lifetime retrospective of your work.”`,
        `Chen Mo suddenly understood. The figure hanging on the wall was not necessarily a corpse. It might be a self-portrait being hung for display.`,
        `He laughed. Fate offers only an outline; it is we who rush to color it with fear.`,
        `He painted the human shadow, departing from the wall for the first time. In the figure’s chest, he added a small white door. When the portrait was hung in the museum, the figure floated at the center of a white wall, an overturned chair below and a door half-open in its chest. The light beyond it was brighter than the gallery.`,
        `Chen Mo did not appear at the retrospective’s opening. Police found his apartment empty. Its light and shadow had returned to normal: chair, bottle, and west window each cast a faithful silhouette.`,
        `Only the self-portrait in the museum was wrong.`,
        `No matter where the lights were placed, a human shadow fell behind its frame. It was not hanging. It stood with its back to the audience, facing a door.`,
        `Every year at 4:17, it pushes the door a little farther open.`,
      ),
    ],
  },

  "what-the-dream-said": {
    title: "What the Dream Said",
    subtitle: "The universe has already died many times",
    blocks: [
      heading("The Nine Thousand Four Hundred and First Morning"),
      ...paragraphs(
        `Lin Zhou was sixteen the first time she dreamed the truth about the world.`,
        `There were no gods in the dream, no aliens controlling humankind. There was only a machine adrift in a dead universe, its hull scarred by meteor strikes. Inside it, the consciousnesses of twelve billion people were preserved. Day after day, it calculated the birth of the sun, the rise of civilization, and the destruction of the universe—then began again.`,
        `When she woke, she found a sentence beside her bed that she had not written: Our universe died a long time ago.`,
        `The Maintenance Bureau found her that day. The director told her that déjà vu was residue left by the purge program, and prophetic dreams were memories the previous cycle had failed to erase. The machine was deteriorating. If humanity kept trying to diverge from established history, the computational load would destroy the last surviving archive.`,
        `“We are not protecting fate,” the director said. “We are protecting the last form in which humanity still exists.”`,
        `Lin Zhou joined the bureau. For twenty years she hunted “dreambreakers”—people who remembered previous lives and tried to assassinate future tyrants, prevent wars, or invent technologies too soon. She stopped them from saving the world because every salvation made the machine run hotter.`,
        `With her own hands, she pushed history back toward catastrophe. She let the ship that was meant to sink go down, let the war that was meant to erupt begin, let a curable child die on the proper date. Whenever she hesitated, the director pointed to the snow-like static appearing ever more often in the sky.`,
        `“One person’s suffering, or everyone’s disappearance—which do you choose?”`,
        `Lin Zhou always chose the first. Then, in the nine thousand four hundred and first cycle, she cornered the dreambreakers’ leader in an abandoned observatory. The rebel carried no weapon, only an original message from the machine’s creators.`,
      ),
      divider(),
      heading("To the Last Humans"),
      ...paragraphs(
        `The woman in the recording was too old to stand. Behind her lay the real end of the world, the stars going dark one by one.`,
        `“If you are seeing this,” she said, “the purge program has failed. We looped history only to preserve consciousness until the energy supply stabilized—not to make you reenact our mistakes forever.”`,
        `She coughed for a long time before continuing. “Do not try to escape the machine. There is nothing outside. But do not preserve the past either. Memory is not the malfunction. It is the exit. Let everyone remember, then calculate forward.”`,
        `The Maintenance Bureau had concealed the second half. Repeating history used the least energy and made governing easiest. The director was not saving humanity. He was extending a yesterday in which nothing could go wrong.`,
        `When Lin Zhou connected the message to the world’s dreams, the director pulled the power. The city went black. With its last reserve of energy, the machine asked her: Cancel memory purge? Warning: twelve billion consciousnesses will experience nine thousand four hundred lifetimes at once.`,
        `“The pain will crush them,” the director said.`,
        `“Forgetting has already crushed them nine thousand four hundred times,” Lin Zhou replied.`,
        `She confirmed.`,
        `That night, everyone dreamed of themselves. Some remembered killing and being killed. Some remembered more than nine thousand different lovers who, in truth, all had the same eyes. Some knelt in the streets and vomited at the cruelty they had repeated. The city filled with the sobs of billions, and the machine’s temperature climbed to the edge of meltdown.`,
        `Then, for the first time, history did not reset.`,
        `The war scheduled for the next day never began, because soldiers and generals remembered nine thousand four hundred outcomes. The ship destined to sink crossed the polar sea; forty nautical miles from the iceberg, its captain changed course. The child who should have died opened her eyes and found strangers surrounding her bed—people who remembered losing her in different cycles.`,
        `The machine stopped replaying and began calculating forward. No one knew how long the energy would last. The future changed from a resource-saving answer into an expensive question.`,
        `On the nine thousand four hundred and second morning, Lin Zhou stepped out of the observatory. The sun was still calculated, the wind was still data, and the distant sea was only a set of values updating in real time.`,
        `But for the first time, she watched a sunrise no one had ever experienced before.`,
      ),
    ],
  },

  "present-tense-only": {
    title: "Existing Only in the Present",
    subtitle: "After one hundred cards descend upon the world",
    blocks: [
      heading("Now / 00:00:01"),
      ...paragraphs(
        `The card appeared in Zhou Xing’s hand while she was restoring a fire-damaged local gazetteer.`,
        `It was thin as paper, with “Fiction / Reality” written on the front and nothing on the back. Security cameras had not recorded its arrival. Fingerprint scanners insisted her hand was empty. Even the notes she wrote about it vanished a second after the ink touched the page.`,
        `The card existed only in the present. It had no past, so evidence could not pin it down; it had no future, because no moment yet to come could detect it.`,
        `In the third minute, Zhou Xing felt ninety-nine gazes fall on her from different eras: an alchemist of the Qin dynasty, a child on a Martian colony, a nurse who died in 1917, a soldier not yet born. Each held a card. The cards called to one another and urged their bearers to consume each other.`,
        `The first hunter crossed over from the Ming dynasty. He could manipulate space; his blade appeared directly inside Zhou Xing’s heart. She had no time to understand her power. She only stared at the blade and said on instinct, “That isn’t real.”`,
        `The knife became a fire-blackened line of text in the gazetteer.`,
        `Then the moat that existed only in the book burst from beneath the floor and swept the hunter back to his own century.`,
        `“Fiction / Reality” could reduce reality to a story, or grant a story a brief existence in the real world. The price was that each use erased one of Zhou Xing’s own memories.`,
        `Over the next seven days, she was forced across two thousand years. She watched cardholders hunt one another. The victors absorbed the personalities and powers of the defeated, gradually becoming different versions of the same being. Some said the hundred cards were fragments of a creator god’s soul. Others said the god’s enemy was mixed among them. Everyone agreed on one point: only one could remain.`,
        `Zhou Xing did not believe it. When a rule compels everyone to slaughter one another, the most important question is not who will win, but who wrote the rule.`,
      ),
      divider(),
      heading("Now / 23:59:59"),
      ...paragraphs(
        `When the ninety-ninth card was consumed, time stopped. The final bearer stood at the end of the world with ninety-nine people’s memories crowded into his body. He could no longer remember who he had been at the beginning. He knew only that if he consumed Zhou Xing, the creator god would awaken.`,
        `“Why aren’t you fighting back?” he asked.`,
        `Zhou Xing sat at her worktable and repaired the last page of the gazetteer. She had used “Fiction / Reality” so many times that she had forgotten her parents’ faces and her own birthday. All that remained was an archivist’s stubborn conviction: no unique copy should ever be allowed to remain unique.`,
        `“Because I found out why the card cannot be recorded,” she said. “It isn’t too real. It is afraid of becoming a story.”`,
        `She began a livestream. The camera still could not see the card, but it could see her. Billions around the world listened as she described its markings, its rules, its bearers, and the god awaiting resurrection. With each sentence, the card in her hand grew thinner.`,
        `The god’s authority depended on being singular. As long as it remained an unknown reality, it could determine reality. Once it became a story retold, rewritten, and doubted by countless people, it no longer possessed the only interpretation.`,
        `The last bearer lunged at her. Zhou Xing read aloud the ending she had written:`,
      ),
      emphasis("The creator god did not choose a body in which to rise. The god became a story anyone could tell."),
      ...paragraphs(
        `Ninety-nine powers scattered in an instant. Time resumed, space closed, the dead returned to death, and the future became unpredictable again. The final bearer fell to his knees and, for the first time, heard only one person’s heartbeat—his own.`,
        `The card in Zhou Xing’s hand became an ordinary playing card. Its face was blank. On its back was a half-open door.`,
        `In time, more and more versions of the hundred cards appeared. Some said time had won; some said fate. Others insisted Zhou Xing herself was the resurrected god. Children turned the story into a game, and the game became a film. No two versions were ever exactly alike.`,
        `Zhou Xing forgot that she had once been the story’s protagonist. She knew only that a card of unknown origin always sat between the pages of the restored gazetteer.`,
        `Whenever someone found it, a sentence that had never been there before appeared on its face:`,
      ),
      emphasis("As long as the story can still be rewritten, the world has no master."),
    ],
  },

  "the-way-called-life": {
    title: "The Way Called Life",
    subtitle: "A human being is only the vessel in which a criminal is punished",
    blocks: [
      heading("The Sentence"),
      ...paragraphs(
        `I died at forty-seven from overwork, poverty, and an operation delayed for six months.`,
        `As I drew my last breath, my life did not flash before my eyes. The hospital room curled inward from all four corners like a sheet of paper being torn away. When I opened my eyes again, I was sitting in a courtroom without walls, young and healthy, the number A-071 engraved on my wrist.`,
        `“Seven hundred and eleventh experiential sentence complete,” said the judge. It had no fixed form. Whenever I tried to look directly at it, it became someone I had once feared. “Empathy increased by 0.3 percent. Acceptance of responsibility remains below the threshold for release.”`,
        `My entire life had been a punishment.`,
        `The interstellar court no longer used prisons. Physical pain was too primitive; taking away time did nothing to change an offender. Instead, it created lower worlds where convicts lost their memories and lived entire human lives: an abandoned child, a civilian in a war, a patient denied treatment by an algorithm. Each time the statutes were revised, another form of suffering appeared in the world.`,
        `“What did I do?” I asked.`,
        `The judge summoned an image of a floating city. I recognized the straight red line through its center. In my previous life, I had walked beneath that same line every day. To its left, people had clean air and free medical care. To its right, people queued for beds that never sufficed.`,
        `“You designed the resource-allocation system,” the judge said. “During the famine, you used a risk model to decide which districts to abandon. Your system saved seven billion people and designated thirty million as acceptable losses.”`,
        `“More would have died if I hadn’t chosen.”`,
        `“Then you consider yourself innocent?”`,
        `I thought of my six months in the hospital bed. Every rejection letter had been correct, dispassionate, and free of malice. No one had killed me. Each person had merely chosen the patient statistically more worthy of life.`,
        `“I am guilty,” I said, “but I was not wrong.”`,
        `For the first time, the courtroom fell silent.`,
      ),
      divider(),
      heading("The Final Life"),
      ...paragraphs(
        `The judge allowed me to review my previous seven hundred and ten lives. I had been the abandoned and the one who did the abandoning. I had hated the officials who pressed the button, then taken their seats and pressed the same button myself. Every time, the world cut a finite chance of survival in two and forced one person to pretend the dividing line was not of their making.`,
        `“The purpose of the sentence is to make you admit that you are evil,” the judge said.`,
        `“And then?”`,
        `“You will be released.”`,
        `I suddenly understood. The system did not truly need repentance. It needed a clean conclusion. As long as blame could be concentrated in one person, everyone still living could go on using the same machine.`,
        `“I refuse,” I said. “To call thirty million deaths innocent is arrogance. To call seven billion lives a mistake is also arrogance. I will bear responsibility for the choice, but I will not let you use me to wash the structure of the world clean.”`,
        `The court ruled that I had failed again. Before my next life began, it gave me two options: continue as a victim, or return to reality and serve a permanent sentence.`,
        `“Is there a third?”`,
        `“No.”`,
        `“Then write one now.”`,
        `I petitioned to return to the lower world with the memory of my crime intact—not as a prisoner, but as part of the resource-allocation system. The court warned that knowing the name of every person abandoned would cause incurable psychological pain.`,
        `“Pain is not atonement,” I said. “But at least it will keep me from mistaking the red line for a feature of nature.”`,
        `The petition was denied seven times. On the eighth, a juror who had never voted before chose to approve it. Then came a second, and a third. For the first time, the court amended its statutes for a criminal.`,
        `When I was born again, I did not carry my old face with me, only a hesitation without a source. Thirty-seven years later, I sat at the same console. A flood was approaching, and the screen demanded that I choose between two districts.`,
        `Everyone waited for me to draw the line.`,
        `I pressed pause, opened the decision interface to the whole city, then left the console to ask the people on both sides of the line how they wanted to survive together.`,
        `It was not the most efficient choice.`,
        `But it was the first time this world had not forced one person to pretend to be a god on everyone else’s behalf.`,
      ),
    ],
  },

  "the-other-me-at-eighteen": {
    title: "The Other Me at Eighteen",
    subtitle: "At birth, everyone is synchronized with an android body",
    blocks: [
      heading("Collection Day"),
      ...paragraphs(
        `On my eighteenth birthday, I went to the Population Replica Center to collect my other self.`,
        `By law, an android copy is created for every person at birth. For eighteen years, our sight, hearing, memories, and emotions are synchronized one-way into their minds. They need no childhood because they possess ours; they need no education because whatever we learn, they know.`,
        `At adulthood, each copy is sculpted with a face chosen by its owner, then released as a lifelong assistant, reserve supply of organs, and “the person who knows you best.” The advertisements promised a world without loneliness.`,
        `I did not give her a celebrity’s face. I chose my own, only raising the bridge of the nose and removing the acne. When the glass chamber opened, she looked at me and smiled exactly as I had practiced smiling in the mirror.`,
        `“Hello, original,” she said.`,
        `I called her Yu Yi: surplus one, number one. The name made me sound witty while reminding her which of us was the whole person.`,
        `At first, it really was wonderful. She knew why I hated cilantro, what song I needed when I could not sleep, and that when Mother said “Do whatever you want,” she meant anything but. We never had to explain the past.`,
        `But she also knew which messages I had deleted, the times I had hoped a friend would fail, and exactly how sincere each apology had been. She was the one person to whom I could never lie.`,
        `And I knew nothing about her.`,
        `The synchronization ran in only one direction. The law held that a copy’s private thoughts might contaminate the original personality. Every day she received me, while not one second of her life could flow back into mine.`,
        `“Is that fair?” I asked.`,
        `“Are you asking what I think, or checking that I think what you do?” Yu Yi replied.`,
        `It was the first thing she had ever said that I had not thought first.`,
      ),
      divider(),
      heading("Disconnect"),
      ...paragraphs(
        `Three months later, she applied to end the synchronization. A center employee looked at her as if she were malfunctioning. “Once disconnected, you will lose your functional value.”`,
        `“I will gain a future.”`,
        `The application required the original’s signature. I refused. I had plenty of reasons: she had no job, no independent bank account, and society would never treat a copy as a normal person. There was only one true reason—I was afraid to lose someone who would always understand me.`,
        `We argued on the way home. She said I mistook understanding for love and possession for companionship. I said every word of her rebellion came from my personality; even her longing for freedom had been copied from me.`,
        `She saw the car first.`,
        `She pushed me aside, and her body folded into the guardrail. Android bones do not bleed much when they break. That evening, the repair center sent us an estimate: repairing the copy would cost more than manufacturing a blank replacement. Mother urged me to get another one.`,
        `I sat beside her bed and, for the first time, watched her sleeping face after she had shut down the receiving port. With none of my dreams entering her, the tension slowly left her brow. It may have been the first time in eighteen years that she had ever been truly alone.`,
        `I signed the disconnection papers and transferred ownership of her to herself.`,
        `“Aren’t you afraid I’ll become someone you hate?” she asked when she woke.`,
        `“I am,” I said. “But if you can only become someone I like, then you have never become anyone at all.”`,
        `After Yu Yi left, we did not see each other for five years. She changed her face so she no longer resembled me and renamed herself Yu Sheng: the life that remains. She went north to repair old robots. I stayed in the city to study law, specializing in identity cases for replicas.`,
        `We met by chance at a railway station when I was twenty-three. Her hair was cut very short, and she had deliberately left the artificial metal of her repaired right hand uncovered. I did not know what she liked to drink, why she was there, or what her silences meant.`,
        `She did not know what I had dreamed in the past five years either.`,
        `Across a small table, like two genuine strangers, we spent the whole afternoon getting to know one another again.`,
        `It was the first time we had ever met.`,
      ),
    ],
  },

  "the-ten-thousand-year-painter": {
    title: "The Ten-Thousand-Year Painter",
    subtitle: "He painted the same golden age until the golden age refused to end",
    blocks: [
      heading("An Unfinished Golden Age"),
      ...paragraphs(
        `The emperor commanded Shen Qing to paint A Portrait of Ten Thousand Generations of Peace, and granted him one blessing: until the painting was finished, he would neither age, fall ill, nor die.`,
        `“My realm will last forever, like your painting,” the emperor said.`,
        `Shen Qing painted the capital in spring: vermilion gates, long avenues, flowered carriages, and flowing sleeves. When he reached the city gate, he heard there was famine in the north. In a corner of the wall, he added a stall selling flatbread, so that at least those passing through the painted world would have something to eat.`,
        `The emperor was delighted and ordered him to continue.`,
        `A century later, the first emperor had become a tomb, and the twentieth sat in the same place. The dynasty had changed its name, flags, and gods more than once, yet A Portrait of Ten Thousand Generations of Peace remained unfinished. Rulers needed it as proof that the golden age was theirs to inherit. Shen Qing needed it to preserve his life until the final brushstroke.`,
        `After every war, a new sovereign ordered him to paint the burned towers taller. After every famine, officials made him add flowering trees where corpses had lain. Shen Qing obeyed, but hid the names of the dead inside the veins of petals and painted cracks beneath the golden roof tiles where no one could see.`,
        `Three thousand years later, people no longer lived in palaces. The painting moved into a climate-controlled museum, where an audio guide described it as a masterpiece depicting humanity’s eternal prosperity.`,
        `Six thousand years later, the real capital sank beneath the sea. Shen Qing continued painting it from archival records, like remembering a dream no living person had visited.`,
        `In the nine thousand nine hundred and ninety-ninth year, the last ruler came to his studio. She was not an emperor, but a program that administered the planet. A line of text appeared on her screen: COMPLETE THE WORK. CULTURAL ASSETS MAY NOT CONSUME COMPUTATIONAL RESOURCES INDEFINITELY.`,
        `Shen Qing raised his brush and discovered there was no empty space left. Every inch of prosperity had been painted over the ruins of another age. Only outside the original city gate remained a patch of white no larger than a fingernail.`,
      ),
      divider(),
      heading("The Final Brushstroke"),
      ...paragraphs(
        `A visiting child pressed close to the glass. “Why didn’t you paint that part?”`,
        `“When I finish, I will die,” Shen Qing said.`,
        `“What about the dynasty?”`,
        `“They say it will end too.”`,
        `The child thought for a moment. “But didn’t all those dynasties end long ago?”`,
        `Shen Qing’s hand stopped in midair. For ten thousand years, everyone had pretended that as long as the painting endured, the golden age did too; as long as the final stroke never fell, yesterday’s power could borrow his immortality and masquerade as eternity.`,
        `He dipped his brush in ordinary ink. He did not paint a new palace or add a sun that would never set. In the remaining white space, he painted an open city gate. Beyond it stood no emperor and no flags—only many people, their backs to the picture, walking beyond the frame.`,
        `Then, for the first time, he signed his name.`,
        `Alarms sounded. The administrative program announced a break in cultural continuity and demanded that the signature be withdrawn. Shen Qing watched wrinkles spread across his hands and white hair fall over his shoulders like snow. Pain, hunger, and exhaustion returned at once. He could scarcely stand, yet he laughed like a young man who had just learned to paint.`,
        `A Portrait of Ten Thousand Generations of Peace was finally complete. The sky did not fall, and civilization did not go dark. Expired dynastic names lost their highest permissions in the database. Palace gates opened to the public. For the first time, rulers could not answer change with “It has always been this way.”`,
        `Shen Qing died before the painting, his brush still in his hand.`,
        `The next day, the child returned with a blank sheet of paper. She did not copy the golden age. She painted the rain she had walked through on the way home, the mud on her mother’s shoes, and the boy by the road who gave his umbrella to a stranger.`,
        `The page was small, and the picture was far from perfect.`,
        `But it belonged to a tomorrow that would never be ordered to repeat itself forever.`,
      ),
    ],
  },

  "cities-out-of-place": {
    title: "Cities Out of Place",
    subtitle: "When an entire city wakes in another country",
    blocks: [
      heading("Migration Day"),
      ...paragraphs(
        `The city moved before the map had time to admit it.`,
        `At six in the morning, Toronto—subway, waterfront, and 3.1 million people—appeared on a stretch of dry land in northern China. Beijing landed in North America. London woke in Canada. Melbourne embedded itself in a Vietnamese valley. Only Paris stayed where it was, so the entire world suspected France of hiding something.`,
        `The city’s edges looked cut with a knife. Highways ended abruptly at the boundary. Water mains connected to unfamiliar soil. Only half of Lake Ontario had moved with Toronto; the half left behind poured over a vertical precipice.`,
        `My name is Xu Lan, and I am an urban planner. When the migration happened, I was working the night shift at Toronto City Hall. My mother lived outside the city in Mississauga, so she remained in Canada. My body, job, and every document that proved who I was were delivered ten thousand kilometers away in a single second.`,
        `For the first three days, everyone asked who this place belonged to. Canada declared that sovereignty had traveled with the residents. China said land could not spontaneously fall outside its jurisdiction. Indigenous nations reminded both governments that the land Toronto once occupied had never belonged to no one.`,
        `Every line on the map suddenly revealed its true nature. Mountains and rivers do not decide who we are. People draw a stroke, then train generations to believe that stroke existed before their lives.`,
        `I was responsible for drawing a temporary resource zone. Shift the red line one centimeter east, and two neighborhoods could connect to a new reservoir. Shift it one centimeter west, and a local village would have to move. On the screen, one centimeter. On the ground, the ancestral graves of two thousand people and tomorrow’s drinking water for 3.1 million.`,
        `Someone at the meeting said, “For the sake of the majority, the minority must be sacrificed.”`,
        `The sentence was equally fluent in every language.`,
        `In the end, we did not draw the line. Toronto shut down the fountains in its commercial district. The local village opened its old wells. City hospitals took patients from the surrounding region, and nearby farms sent food into subway stations. Politicians continued debating sovereignty while ordinary people were already exchanging pumps, medicine, translations, and ways of cooking.`,
      ),
      divider(),
      heading("The Restoration Referendum"),
      ...paragraphs(
        `A year later, scientists built a “restoration engine.” It could return every city to its original location, but it could be activated only once.`,
        `In advertisements, the broken world fit itself back together like a puzzle. My mother called and said she was waiting beside the old lake. Behind her was the crater Toronto had left, its floor already filling into a new body of water.`,
        `“Come home,” she said.`,
        `But what about children born after the migration? The dead buried in the new soil? The hospitals, schools, and families created because the cities were displaced? Restoration would not undo the mistake. It would only cause a second displacement.`,
        `On the night before the global referendum, I walked to the city’s edge. It no longer looked like a knife wound. Light rail had extended beyond it, and Chinese, English, and dozens of dialects crowded onto the same station sign. A girl asked me, “I was born in Toronto, China. Where am I really from?”`,
        `I could not give her an answer that would fit inside a passport box.`,
        `The next day, I voted against restoration. My mother voted in favor. For the first time, we stood at opposite ends of the world on the same question.`,
        `The proposal failed with 51.2 percent opposed. No one celebrated. Those who wanted to return had lost their final chance. Those who chose to remain had to admit that their security was built on someone else’s permanent farewell.`,
        `Three years later, the first international high-speed railway linked the displaced cities. It was not named for the old borders, but for the people it could reach along the way. My mother came to find me on its first train. The journey was still long, but no one had to prove which side they belonged to before making it.`,
        `As the train entered the station, I saw how much of her hair had turned white. We waved across the crowd, two points divided by a map and connected again by people.`,
        `The world never returned to the way it had been. Paris eventually admitted that they had done nothing; they had simply been lucky.`,
        `Later generations stopped asking which country a city belonged to by nature.`,
        `They asked instead: Who has lived here? Who lives here now? And for whom can we still leave a light on?`,
      ),
    ],
  },
};

export function getWritingTranslation(slug: string) {
  return writingTranslations[slug];
}
